# A few create_and_poll methods re-fetch the parent and search a nested
# collection for the just-created child (baremetal servers via list .results,
# pool members via pool.members, security-group rules via .security_group_rules).
# The superset below carries CREATED_ID in each; unrelated resources ignore it.
_RESOURCE: dict[str, Any] = {
    "count": 1,
    "results": [{"id": CREATED_ID}],
    "members": [{"id": CREATED_ID}],
    "security_group_rules": [{"id": CREATED_ID}],
    # instances.images.upload_and_poll re-polls the image until it settles
    # (status == "active" and size); other methods ignore these extra fields.
    "status": "active",
    "size": 10,
}


def _handler(request: httpx.Request) -> httpx.Response:
    path = request.url.path
    if request.method == "GET" and "/tasks/" in path:
        return httpx.Response(200, json=_TASK)
    if request.method == "GET":
        return httpx.Response(200, json=_RESOURCE)
    return httpx.Response(200, json={"tasks": ["task-1"]})  # the action


