_IDS = [c[0] for c in AND_POLL_CASES]

# *_and_poll helpers that delegate to a base method the API has deprecated;
# calling them emits DeprecationWarning (same as the base method itself).
_DEPRECATED_CASE_IDS = {
    "cloud.gpu_baremetal.clusters.rebuild_and_poll",
    "cloud.gpu_baremetal.clusters.servers.rebuild_and_poll",
}


@pytest.mark.parametrize(("case_id", "invoke"), AND_POLL_CASES, ids=_IDS)
def test_and_poll_sync(case_id: str, invoke: Callable[[Any], Any]) -> None:
    client = Gcore(base_url=base_url, api_key="test", _strict_response_validation=False)
    with respx.mock(base_url=base_url) as router:
        router.route(url__regex=r".+").mock(side_effect=_handler)
        if case_id in _DEPRECATED_CASE_IDS:
            with pytest.warns(DeprecationWarning):
                invoke(client)  # must not raise
        else:
            invoke(client)  # must not raise


@pytest.mark.parametrize(("case_id", "invoke"), AND_POLL_CASES, ids=_IDS)
async def test_and_poll_async(case_id: str, invoke: Callable[[Any], Any]) -> None:
    client = AsyncGcore(base_url=base_url, api_key="test", _strict_response_validation=False)
    with respx.mock(base_url=base_url) as router:
        router.route(url__regex=r".+").mock(side_effect=_handler)
        if case_id in _DEPRECATED_CASE_IDS:
            with pytest.warns(DeprecationWarning):
                await invoke(client)  # must not raise
        else:
            await invoke(client)  # must not raise


